-- ═══════════════════════════════════════════════════════════════
-- SABIE — Banco de actividades de primaria
-- Ejecutar en: Supabase → SQL Editor → Run  (idempotente)
--
-- Qué hace: 1) bucket PRIVADO 'actividades' en Storage
--           2) política: solo usuarios autenticados pueden LEER
--           3) tabla lv_actividades + RLS + trigger
--           4) catálogo con los archivos curados
--
-- DESPUÉS de correr esto: Supabase → Storage → actividades →
-- arrastra las carpetas que están DENTRO de 'Subir_a_Supabase'
-- (la carpeta que Claude creó en el proyecto).
-- ═══════════════════════════════════════════════════════════════

values ('actividades','actividades', false)
on conflict (id) do nothing;

drop policy if exists "actividades_lectura_autenticados" on storage.objects;
create policy "actividades_lectura_autenticados" on storage.objects
  for select to authenticated using (bucket_id = 'actividades');

create table if not exists lv_actividades (
  id             text primary key,
  datos          jsonb,
  actualizado_en timestamptz default now()
);
drop trigger if exists tg_actualizado_en on lv_actividades;
create trigger tg_actualizado_en before insert or update on lv_actividades
  for each row execute function public.tocar_actualizado_en();
alter table lv_actividades enable row level security;
drop policy if exists "solo_autenticados" on lv_actividades;
create policy "solo_autenticados" on lv_actividades
  for all to authenticated using (true) with check (true);

on conflict (id) do update set datos = excluded.datos;

select count(*) as actividades_cargadas from lv_actividades;
